"""
Self-Verification Engine for Think Mode
Provides research workflow verification and accuracy protection layers
"""
import re
import asyncio
from dataclasses import dataclass
from typing import Dict, List, Any, Optional, Tuple
from enum import Enum

class VerificationLevel(Enum):
    """Levels of verification rigor"""
    BASIC = "basic"           # Simple consistency check
    ENHANCED = "enhanced"     # Fact verification and logic check
    RIGOROUS = "rigorous"     # Comprehensive verification with sources
    CRITICAL = "critical"     # Maximum verification for sensitive topics

class VerificationResult(Enum):
    """Results of verification process"""
    VERIFIED = "verified"           # Information is accurate and consistent
    PARTIALLY_VERIFIED = "partial" # Some concerns but generally accurate
    QUESTIONABLE = "questionable"   # Significant concerns found
    REJECTED = "rejected"           # Contains errors or inconsistencies

@dataclass
class VerificationReport:
    """Report from verification process"""
    result: VerificationResult
    confidence_score: float        # 0.0 - 1.0
    verified_claims: List[str]
    questionable_claims: List[str]
    factual_errors: List[str]
    logical_inconsistencies: List[str]
    source_reliability: Dict[str, float]
    recommendations: List[str]
    processing_notes: str

@dataclass
class ResearchContext:
    """Context for research verification"""
    original_query: str
    research_findings: str
    reasoning_process: str
    sources_cited: List[str]
    complexity_score: float
    research_depth: str

class SelfVerificationEngine:
    """
    Advanced verification system for think mode research workflows
    Provides multiple layers of verification and accuracy checking
    """

    def __init__(self):
        # Sensitive topics requiring enhanced verification
        self.sensitive_topics = {
            'medical', 'health', 'medication', 'treatment', 'diagnosis',
            'financial', 'investment', 'trading', 'tax', 'legal',
            'safety', 'security', 'emergency', 'crisis',
            'political', 'controversial', 'sensitive',
            'nuclear', 'chemical', 'weapons', 'explosive'
        }

        # Fact-checking patterns
        self.fact_indicators = [
            r'\d+\%',  # Percentages
            r'\d+\s*(?:million|billion|thousand)',  # Large numbers
            r'according\s+to',  # Source attribution
            r'research\s+shows',  # Research claims
            r'studies\s+indicate',  # Study claims
            r'proven\s+to',  # Certainty claims
            r'always\s+|never\s+',  # Absolute statements
            r'all\s+.*\s+are',  # Universal statements
        ]

        # Logic consistency patterns
        self.logical_patterns = [
            r'because\s+.*\s+therefore',  # Causal reasoning
            r'if\s+.*\s+then',  # Conditional logic
            r'not\s+only\s+.*\s+but\s+also',  # Additive logic
            r'either\s+.*\s+or',  # Alternative logic
            r'while\s+.*\s+however',  # Contrasting logic
        ]

    async def verify_research_workflow(self, research_context: ResearchContext) -> VerificationReport:
        """
        Main verification workflow for think mode research
        """
        # Determine verification level based on content sensitivity
        verification_level = self._determine_verification_level(
            research_context.original_query,
            research_context.research_findings
        )

        # Initialize verification components
        verified_claims = []
        questionable_claims = []
        factual_errors = []
        logical_inconsistencies = []
        recommendations = []

        # Step 1: Content consistency verification
        consistency_score = await self._verify_content_consistency(
            research_context.original_query,
            research_context.research_findings,
            research_context.reasoning_process
        )

        # Step 2: Factual claim verification
        factual_score, fact_issues = await self._verify_factual_claims(
            research_context.research_findings
        )
        factual_errors.extend(fact_issues)

        # Step 3: Logical reasoning verification
        logic_score, logic_issues = await self._verify_logical_reasoning(
            research_context.reasoning_process
        )
        logical_inconsistencies.extend(logic_issues)

        # Step 4: Source reliability assessment
        source_reliability = await self._assess_source_reliability(
            research_context.sources_cited
        )

        # Step 5: Completeness verification
        completeness_score = await self._verify_completeness(
            research_context.original_query,
            research_context.research_findings
        )

        # Calculate overall confidence score
        confidence_score = (
            consistency_score * 0.25 +
            factual_score * 0.25 +
            logic_score * 0.25 +
            completeness_score * 0.25
        )

        # Adjust for source reliability
        if source_reliability:
            avg_source_reliability = sum(source_reliability.values()) / len(source_reliability)
            confidence_score = confidence_score * (0.8 + 0.2 * avg_source_reliability)

        # Determine verification result
        result = self._determine_verification_result(
            confidence_score, factual_errors, logical_inconsistencies
        )

        # Generate recommendations
        recommendations = self._generate_recommendations(
            result, confidence_score, verification_level,
            factual_errors, logical_inconsistencies
        )

        # Create processing notes
        processing_notes = self._create_processing_notes(
            verification_level, consistency_score, factual_score,
            logic_score, completeness_score
        )

        return VerificationReport(
            result=result,
            confidence_score=confidence_score,
            verified_claims=verified_claims,
            questionable_claims=questionable_claims,
            factual_errors=factual_errors,
            logical_inconsistencies=logical_inconsistencies,
            source_reliability=source_reliability,
            recommendations=recommendations,
            processing_notes=processing_notes
        )

    def _determine_verification_level(self, query: str, content: str) -> VerificationLevel:
        """Determine appropriate verification level based on content"""
        combined_text = (query + " " + content).lower()

        # Check for sensitive topics
        sensitive_count = sum(1 for topic in self.sensitive_topics if topic in combined_text)

        if sensitive_count >= 3:
            return VerificationLevel.CRITICAL
        elif sensitive_count >= 2:
            return VerificationLevel.RIGOROUS
        elif sensitive_count >= 1:
            return VerificationLevel.ENHANCED
        else:
            return VerificationLevel.BASIC

    async def _verify_content_consistency(self, query: str, findings: str, reasoning: str) -> float:
        """Verify consistency between query, findings, and reasoning"""
        consistency_score = 1.0

        # Check if findings address the original query
        query_words = set(query.lower().split())
        findings_words = set(findings.lower().split())

        # Calculate word overlap (basic relevance check)
        overlap = len(query_words.intersection(findings_words))
        relevance_score = overlap / max(len(query_words), 1)

        # Check reasoning coherence
        reasoning_sentences = reasoning.split('.')
        if len(reasoning_sentences) < 2:
            consistency_score *= 0.8  # Insufficient reasoning

        # Check for contradictions
        contradiction_patterns = [
            r'however.*but',  # Double contradiction
            r'always.*never',  # Absolute contradiction
            r'all.*none',  # Universal contradiction
        ]

        for pattern in contradiction_patterns:
            if re.search(pattern, findings.lower()):
                consistency_score *= 0.7

        return min(1.0, consistency_score * relevance_score)

    async def _verify_factual_claims(self, content: str) -> Tuple[float, List[str]]:
        """Verify factual claims in the content"""
        factual_score = 1.0
        issues = []

        # Check for unsubstantiated claims
        absolute_patterns = [
            r'always\s+\w+',
            r'never\s+\w+',
            r'all\s+\w+\s+are',
            r'no\s+\w+\s+can',
            r'everyone\s+knows',
            r'it\s+is\s+proven\s+that'
        ]

        for pattern in absolute_patterns:
            matches = re.findall(pattern, content.lower())
            for match in matches:
                issues.append(f"Absolute claim without qualification: '{match}'")
                factual_score *= 0.9

        # Check for unsupported statistics
        stat_patterns = [
            r'\d+\%\s+of\s+\w+',
            r'\d+\s+times\s+more',
            r'increases?\s+by\s+\d+\%'
        ]

        for pattern in stat_patterns:
            matches = re.findall(pattern, content.lower())
            for match in matches:
                if 'according to' not in content.lower() and 'source' not in content.lower():
                    issues.append(f"Statistic without source: '{match}'")
                    factual_score *= 0.85

        return factual_score, issues

    async def _verify_logical_reasoning(self, reasoning: str) -> Tuple[float, List[str]]:
        """Verify logical consistency in reasoning"""
        logic_score = 1.0
        issues = []

        # Check for logical fallacies
        fallacy_patterns = [
            (r'because\s+.*\s+everyone\s+does\s+it', "Appeal to popularity"),
            (r'if\s+you\s+don\'t\s+.*\s+then\s+.*\s+will\s+happen', "False dilemma"),
            (r'.*\s+always\s+leads\s+to\s+.*', "Hasty generalization"),
            (r'.*\s+proves\s+that\s+.*\s+is\s+wrong', "Strawman argument pattern"),
        ]

        for pattern, fallacy_name in fallacy_patterns:
            if re.search(pattern, reasoning.lower()):
                issues.append(f"Potential logical fallacy: {fallacy_name}")
                logic_score *= 0.8

        # Check for circular reasoning
        sentences = reasoning.split('.')
        for i, sentence in enumerate(sentences):
            for j, other_sentence in enumerate(sentences[i+1:], i+1):
                # Simple circular reasoning detection
                if (len(sentence.split()) > 5 and len(other_sentence.split()) > 5 and
                    sentence.strip().lower() in other_sentence.lower()):
                    issues.append("Potential circular reasoning detected")
                    logic_score *= 0.85
                    break

        return logic_score, issues

    async def _assess_source_reliability(self, sources: List[str]) -> Dict[str, float]:
        """Assess reliability of cited sources"""
        reliability_scores = {}

        for source in sources:
            source_lower = source.lower()

            # High reliability sources
            if any(domain in source_lower for domain in [
                'nature.com', 'science.org', 'ieee.org', 'pubmed',
                'arxiv.org', 'scholar.google', 'jstor.org'
            ]):
                reliability_scores[source] = 0.9

            # Medium reliability sources
            elif any(domain in source_lower for domain in [
                'wikipedia.org', 'britannica.com', 'reuters.com',
                'bbc.com', 'cnn.com', 'nytimes.com'
            ]):
                reliability_scores[source] = 0.7

            # Lower reliability or unknown sources
            else:
                reliability_scores[source] = 0.5

        return reliability_scores

    async def _verify_completeness(self, query: str, findings: str) -> float:
        """Verify if findings adequately address the query"""
        completeness_score = 1.0

        # Check if key question words are addressed
        question_words = ['what', 'how', 'why', 'when', 'where', 'who']
        query_lower = query.lower()
        findings_lower = findings.lower()

        for word in question_words:
            if word in query_lower:
                # Look for corresponding answer patterns
                answer_patterns = {
                    'what': [r'what\s+is', r'the\s+definition', r'refers\s+to'],
                    'how': [r'how\s+to', r'the\s+process', r'steps\s+include'],
                    'why': [r'because', r'due\s+to', r'the\s+reason'],
                    'when': [r'when', r'during', r'at\s+the\s+time'],
                    'where': [r'where', r'in\s+the', r'at\s+the\s+location'],
                    'who': [r'who', r'the\s+person', r'the\s+individual']
                }

                if word in answer_patterns:
                    patterns_found = any(re.search(pattern, findings_lower)
                                       for pattern in answer_patterns[word])
                    if not patterns_found:
                        completeness_score *= 0.85

        return completeness_score

    def _determine_verification_result(self, confidence_score: float,
                                     factual_errors: List[str],
                                     logical_inconsistencies: List[str]) -> VerificationResult:
        """Determine overall verification result"""

        if confidence_score >= 0.9 and len(factual_errors) == 0 and len(logical_inconsistencies) == 0:
            return VerificationResult.VERIFIED
        elif confidence_score >= 0.7 and len(factual_errors) <= 1 and len(logical_inconsistencies) <= 1:
            return VerificationResult.PARTIALLY_VERIFIED
        elif confidence_score >= 0.5:
            return VerificationResult.QUESTIONABLE
        else:
            return VerificationResult.REJECTED

    def _generate_recommendations(self, result: VerificationResult, confidence_score: float,
                                verification_level: VerificationLevel, factual_errors: List[str],
                                logical_inconsistencies: List[str]) -> List[str]:
        """Generate recommendations based on verification results"""
        recommendations = []

        if result == VerificationResult.VERIFIED:
            recommendations.append("✅ Information verified - safe to proceed")
        elif result == VerificationResult.PARTIALLY_VERIFIED:
            recommendations.append("⚠️ Generally accurate but review flagged items")
            if factual_errors:
                recommendations.append("📋 Verify factual claims before final output")
        elif result == VerificationResult.QUESTIONABLE:
            recommendations.append("🔍 Requires additional verification before use")
            recommendations.append("🔄 Consider re-researching with different sources")
        else:  # REJECTED
            recommendations.append("❌ Contains significant errors - do not use")
            recommendations.append("🔄 Complete re-research required")

        if confidence_score < 0.8:
            recommendations.append("📚 Consider gathering additional sources")

        if verification_level in [VerificationLevel.CRITICAL, VerificationLevel.RIGOROUS]:
            recommendations.append("🛡️ High-stakes topic - extra caution advised")

        return recommendations

    def _create_processing_notes(self, verification_level: VerificationLevel,
                               consistency_score: float, factual_score: float,
                               logic_score: float, completeness_score: float) -> str:
        """Create detailed processing notes"""

        return f"""Verification Analysis:
• Level: {verification_level.value.upper()}
• Consistency: {consistency_score:.2f}
• Factual Accuracy: {factual_score:.2f}
• Logical Coherence: {logic_score:.2f}
• Completeness: {completeness_score:.2f}
• Processing completed with {verification_level.value} verification standards"""

# Global instance
verification_engine = SelfVerificationEngine()